mapper.select:
SELECT sm.movement_id, sm.product_id, sm.warehouse_id, sm.movement_type, sm.qty, sm.unit_cost, sm.ref_order_id, sm.ref_order_type, sm.remarks, sm.created_by, DATE_FORMAT(sm.created_at, '%Y-%m-%d %H:%i') AS created_at, p.product_code, p.product_name, p.unit, w.warehouse_code, w.warehouse_name, m.name AS created_by_name FROM STOCK_MOVEMENT sm INNER JOIN PRODUCT p ON sm.product_id = p.product_id INNER JOIN WAREHOUSE w ON sm.warehouse_id = w.warehouse_id INNER JOIN member m ON sm.created_by = m.member_id
AND (p.product_name LIKE CONCAT('%', #{keyword}, '%') OR p.product_code LIKE CONCAT('%', #{keyword}, '%'))
AND sm.movement_type = #{movementType}
AND sm.warehouse_id = #{warehouseId}
AND DATE(sm.created_at) >= #{fromDate}
AND DATE(sm.created_at) <= #{toDate}
ORDER BY sm.movement_id DESC
